// 动画混合公式
// 对于每个骨骼的每个属性:
finalValue = valueA * weightA + valueB * weightB

// 多动画混合（权重归一化）:
finalValue = sum(value[i] * weight[i])
// 其中 sum(weight[i]) = 1.0

// 对于四元数旋转，使用加权 slerp 或 NLerp:
finalRotation = Quat.normalize(
  Quat.scale(q0, w0) + Quat.scale(q1, w1)
)

// Crossfade 过渡
// duration: 过渡时长（秒）
// elapsed: 已过去的时间
const t = Math.min(elapsed / duration, 1.0);

// 旧动画权重：从 1 到 0
oldState.weight = 1.0 - t;

// 新动画权重：从 0 到 1
newState.weight = t;

// 每帧求值时，两个状态分别乘以各自权重后加到混合缓冲区

// 最短路径四元数插值
function shortestPathSlerp(a: Quat, b: Quat, t: number): Quat {
  let dot = Quat.dot(a, b);

  // 如果点积为负，翻转 b 以走最短路径
  if (dot < 0) {
    b = Quat.negate(b);
    dot = -dot;
  }

  // 如果四元数几乎相同，使用线性插值避免除零
  if (dot > 0.9995) {
    return Quat.normalize(Quat.lerp(a, b, t));
  }

  // 标准 slerp
  const theta = Math.acos(dot);
  const sinTheta = Math.sin(theta);
  return Quat.add(
    Quat.scale(a, Math.sin((1 - t) * theta) / sinTheta),
    Quat.scale(b, Math.sin(t * theta) / sinTheta)
  );
}

// 叠加混合
// additiveClip: 叠加动画（存储的是相对于参考姿态的增量）
// baseClip: 基础动画
// refPose: 参考姿态（通常是 bind pose 或动画第一帧）

// 叠加动画的值已经是增量: delta = current - refPose
// 最终姿态 = 基础姿态 + 增量 * 权重
for (let i = 0; i < bones.length; i++) {
  finalPos[i] = basePos[i] + additiveDelta[i] * weight;
  finalRot[i] = Quat.multiply(baseRot[i], Quat.slerp(Quat.IDENTITY, additiveRotDelta[i], weight));
}

// 动画状态机示例
interface AnimationState {
  name: string;
  clip: AnimationClip;
  loop: boolean;
  speed: number;
}

interface Transition {
  from: AnimationState;
  to: AnimationState;
  duration: number;       // Crossfade 时长
  conditions: Condition[]; // 过渡条件
  exitTime?: number;       // 退出时间（归一化）
  hasExitTime: boolean;    // 是否依赖退出时间
}

interface Condition {
  parameter: string;   // 参数名
  operator: '==' | '>' | '<' | '>=' | '<=';
  value: number | boolean | string;
}

// 使用 AnimationController 控制动画
const controller = node.getComponent(AnimationController);

// 设置速度变量，驱动 Idle/Walk/Run 的过渡
controller.setValue('speed', 3.5);

// 设置布尔变量
controller.setValue('crouching', true);

// 设置触发器（一次性信号）
controller.setValue('attack', true);

// 查询当前状态
const status = controller.getCurrentStateStatus(0);
console.log(`当前动画: ${status?.clip?.name}, 进度: ${status?.progress}`);
